import itertools

class Solution:
    def minimumTime(self, nums1, nums2, x):
        n = len(nums1)
        total1 = sum(nums1)
        total2 = sum(nums2)
        for T in range(n + 1):
            best = None
            for order in itertools.permutations(range(n), T):
                saved = 0
                for slot, idx in enumerate(order, start=1):
                    saved += nums1[idx] + slot * nums2[idx]
                if best is None or saved > best:
                    best = saved
            if best is None:
                best = 0
            if total1 + T * total2 - best <= x:
                return T
        return -1

