var minimumTime = function(nums1, nums2, x) {
    const n = nums1.length;
    const pairs = nums1.map((a, i) => [nums2[i], a]).sort((p, q) => p[0] - q[0]);
    const NEG = -Infinity;
    const dp = new Array(n + 1).fill(NEG);
    dp[0] = 0;
    for (const [b, a] of pairs) {
        for (let k = n; k >= 1; k--) {
            if (dp[k - 1] !== NEG) {
                const cand = dp[k - 1] + a + k * b;
                if (cand > dp[k]) dp[k] = cand;
            }
        }
    }
    const total1 = nums1.reduce((s, v) => s + v, 0);
    const total2 = nums2.reduce((s, v) => s + v, 0);
    for (let T = 0; T <= n; T++) {
        if (dp[T] === NEG) continue;
        if (total1 + T * total2 - dp[T] <= x) return T;
    }
    return -1;
};
